import React, { useState } from "react";
import styles from "./header.module.css";

import Logo from "../logo";
import NavBar from "./nav-bar";
import User from "./user";
import Cart from "./cart";
import { useTranslation } from "react-i18next";

const Header = () => {
  const { i18n } = useTranslation();
  const [activeLanguage, setActiveLanguage] = useState("en"); // Default to "en"

  const changeLanguage = (language: string) => {
    i18n.changeLanguage(language);
    setActiveLanguage(language);
  };

  return (
    <header>
      <section className={styles.header}>
        <div className="container">
          <div className={styles.header__container}>
            <Logo imgSrc="/images/logo-header.svg" width={126} height={34} />
            <NavBar />
            <div className={styles.header__right}>
              <User imgSrc="/images/Profile.svg" link="#" />
              <Cart imgSrc="/images/Cart.svg" link="#" />
              <div className={styles.languageButtons}>
                <button
                  className={`${styles.btn_lang} ${
                    activeLanguage === "en" ? styles.btn_active : ""
                  }`}
                  onClick={() => changeLanguage("en")}
                >
                  EN
                </button>
                <button
                  className={`${styles.btn_lang} ${
                    activeLanguage === "es" ? styles.btn_active : ""
                  }`}
                  onClick={() => changeLanguage("es")}
                >
                  ES
                </button>
              </div>
            </div>
          </div>
        </div>
        <div className={styles.divider} />
      </section>
    </header>
  );
};

export default Header;
